const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{ json: { certificates: [], contracts: [], totalCertificates: 0, totalContracts: 0, totalDocuments: 0, batchId: `BATCH-${Date.now()}`, processedAt: new Date().toISOString(), originalRows: [] } }];
}

const rows = allItems.map((item, index) => ({
  ...item.json,
  _originalRowIndex: index + 2
}));

const certificates = rows
  .filter(r => (r.DocumentType || '').toLowerCase().includes('certificate'))
  .map(r => ({
    name: r.Name || '',
    email: r.Email || '',
    company: r.Company || '',
    role: r.Role || '',
    courseTitle: r.CourseTitle || '',
    completionDate: r.CompletionDate || new Date().toISOString().split('T')[0],
    score: r.Score || '',
    certificateId: `CERT-${Date.now()}-${Math.random().toString(36).substring(2,6).toUpperCase()}`,
    issuedBy: 'Your Organization Name',
    issuerName: 'Your Name'
  }));

const contracts = rows
  .filter(r => (r.DocumentType || '').toLowerCase().includes('contract'))
  .map(r => ({
    name: r.Name || '',
    email: r.Email || '',
    company: r.Company || '',
    role: r.Role || '',
    startDate: r.CompletionDate || new Date().toISOString().split('T')[0],
    contractRef: `CTR-${Date.now()}-${Math.random().toString(36).substring(2,6).toUpperCase()}`,
    issuedBy: 'Your Organization Name',
    issuerName: 'Your Name'
  }));

return [{
  json: {
    certificates,
    contracts,
    totalCertificates: certificates.length,
    totalContracts: contracts.length,
    totalDocuments: certificates.length + contracts.length,
    batchId: `BATCH-${Date.now()}`,
    processedAt: new Date().toISOString(),
    originalRows: rows
  }
}];

const batchData = $('Build Carbone Batch Arrays').first().json;

return [{
  json: {
    attachments: [
      {
        contentType: 'application/vnd.microsoft.card.adaptive',
        content: {
          '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
          type: 'AdaptiveCard',
          version: '1.4',
          body: [
            {
              type: 'TextBlock',
              text: 'Bulk Document Generation Complete',
              weight: 'Bolder',
              size: 'Large',
              color: 'Good'
            },
            {
              type: 'FactSet',
              facts: [
                { title: 'Batch ID',               value: batchData.batchId },
                { title: 'Certificates Generated', value: String(batchData.totalCertificates) },
                { title: 'Contracts Generated',    value: String(batchData.totalContracts) },
                { title: 'Total Documents',        value: String(batchData.totalDocuments) },
                { title: 'Processed At',           value: batchData.processedAt }
              ]
            },
            {
              type: 'TextBlock',
              text: 'All files uploaded to OneDrive. Excel rows updated to Completed.',
              wrap: true,
              color: 'Default'
            }
          ]
        }
      }
    ]
  }
}];

const headerValues = $('Fetch Header Row').first().json.values[0];

const colIndex = {};
headerValues.forEach((name, i) => {
  if (typeof name === 'string' && name.trim()) {
    colIndex[name.trim()] = i;
  }
});

const statusIdx      = colIndex['Status'];
const processedAtIdx = colIndex['ProcessedAt'];

if (statusIdx === undefined || processedAtIdx === undefined) {
  throw new Error(
    `Required columns missing. Found: ${JSON.stringify(colIndex)}. Need: Status, ProcessedAt.`
  );
}

function colLetter(idx) {
  let letter = '';
  let n = idx;
  while (n >= 0) {
    letter = String.fromCharCode(65 + (n % 26)) + letter;
    n = Math.floor(n / 26) - 1;
  }
  return letter;
}

const statusCol    = colLetter(statusIdx);
const processedCol = colLetter(processedAtIdx);

const rows        = $('Build Carbone Batch Arrays').first().json.originalRows;
const workbookId  = $('Config').first().json.workbookId;
const worksheetId = $('Config').first().json.worksheetId;
const now         = new Date().toISOString();

const requests = [];
rows.forEach((row, i) => {
  const excelRow = row._originalRowIndex;
  requests.push({
    id: `status_${i}`,
    method: 'PATCH',
    url: `/me/drive/items/${workbookId}/workbook/worksheets/${worksheetId}/range(address='${statusCol}${excelRow}')`,
    headers: { 'Content-Type': 'application/json' },
    body: { values: [[ 'Completed' ]] }
  });
  requests.push({
    id: `time_${i}`,
    method: 'PATCH',
    url: `/me/drive/items/${workbookId}/workbook/worksheets/${worksheetId}/range(address='${processedCol}${excelRow}')`,
    headers: { 'Content-Type': 'application/json' },
    body: { values: [[ now ]] }
  });
});

// 2 requests per row — chunk at 10 rows to stay under Graph $batch limit of 20
const chunks = [];
for (let i = 0; i < requests.length; i += 20) {
  chunks.push({ json: { requests: requests.slice(i, i + 20) } });
}

return chunks;
